module ALU16(
    input [15:0]D0,
    input [7:0]D1,
    input [2:0]OP,	
    output [15:0]DOUT
    );
	reg [7:0] alu_mux;
	always @*
		case(OP)
			0: alu_mux = 8'h00;	
			1: alu_mux = 8'h01;	
			2: alu_mux = 8'h02;	
			3: alu_mux = D1;		
			4: alu_mux = 8'h00;	
			5: alu_mux = 8'hff;	
			6: alu_mux = 8'hfe;	
			default: alu_mux = 8'hxx;
		endcase
	assign DOUT = D0 + {{8{alu_mux[7]}}, alu_mux};
endmodule
